<template><section class="pipeline"><div v-for="(stage,index) in stages" :key="stage.name" class="pipeline-item" :class="stage.state"><span>{{ stage.state==='done'?'✓':index+1 }}</span>{{ stage.name }}<i v-if="index<stages.length-1">→</i></div></section></template>
<script setup lang="ts">import { computed } from 'vue'; import type { TraceMessage } from '../types'; const props=defineProps<{messages:TraceMessage[]}>(); const defs=[['研究',['research.hypothesis','research.tasks']],['编码',['evolving.codes']],['回测',['feedback.metric','feedback.return_chart']],['反馈',['evolving.feedbacks','feedback.hypothesis_feedback']]]; const stages=computed(()=>{const tags=new Set(props.messages.map(item=>item.tag)); let activeFound=false; return defs.map(([name,required])=>{const done=(required as string[]).some(tag=>tags.has(tag)); const state=done?'done':!activeFound?(activeFound=true,'active'):'idle'; return {name:name as string,state}})})</script>
